const userItem  = $('User Submit').first();
const binary     = userItem.binary || {};
const jobId      = $('Insert row').first().json.job_id;
const actualKeys = Object.keys(binary).filter(k => k.startsWith('file')).sort();
const MAX_FILES  = 5;

const outBinary = {};
for (let i = 0; i < MAX_FILES; i++) {
  const src = actualKeys[Math.min(i, actualKeys.length - 1)];
  outBinary[`file${i}`] = binary[src];
}

return [{ json: { job_id: jobId, file_count: actualKeys.length }, binary: outBinary }];

// Image analyser returns an array of room objects, each containing image_urls.
// Extract the structured image_analysis array and flatten all S3 URLs.
const response = $input.first().json;
const items = Array.isArray(response) ? response : [response];

const imageAnalysis = items.map(item => ({
  room_type:       (item.room_type || 'other').toLowerCase(),
  condition_score: Number(item.condition_score) || 0.0,
  confidence:      Number(item.confidence)      || 0.0,
}));

const imageUrls = items.flatMap(item => item.image_urls || []);

return [{ json: { image_analysis: imageAnalysis, image_urls: imageUrls } }];

// Merge image data (image path) with the original webhook body.
// Falls back to empty image_analysis when no images were submitted.
let imageAnalysis = [];
let imageUrls = '[]';
try {
  const img = $('Parse Image JSON').first().json;
  imageAnalysis = img.image_analysis || [];
  imageUrls = JSON.stringify(img.image_urls || []);
} catch(e) {}

const body = $('User Submit').first().json.body || {};

return [{ json: {
  property_type:  body.property_type || null,
  location:       body.location       || null,
  description:    body.description    || null,
  agent_name:     body.agent_name     || null,
  price_asking:   body.price_asking   != null ? Number(body.price_asking) : null,
  size_sqm:       body.size_sqm       != null ? Number(body.size_sqm)     : null,
  num_rooms:      body.num_rooms      != null ? Number(body.num_rooms)    : null,
  condition:      body.condition      || null,
  intent:         body.intent         || null,
  image_analysis: imageAnalysis,
  _image_urls:    imageUrls,
} }];

const lg        = $('LangGraph Analyze').first().json;
const buildBody = $('Build LangGraph Body').first().json;
const jobId     = $('Insert row').first().json.job_id;

const analysis  = lg.analysis  || {};
const imageUrls = buildBody._image_urls || '[]';

// Text fed to guardrails output check — fields most likely to carry false claims.
const guardrailsText = [
  analysis.market_context,
  analysis.pricing_opinion,
  analysis.recommendation,
].filter(Boolean).join('\n\n');

return [{ json: {
  job_id:          jobId,
  lg_status:       lg.status,
  intent:          lg.intent,
  confidence:      lg.confidence || 0,
  team:            lg.team       || 'unknown',
  deal_score:      lg.deal_score || 0,
  estimated_price: lg.estimated_price || null,
  image_analysis:  JSON.stringify(lg.image_analysis || []),
  image_urls:      imageUrls,
  analysis:        JSON.stringify(analysis),
  guardrails_text: guardrailsText,
} }];
